@Component({
  selector: "app-upload-folders",
  templateUrl: "./upload-folders.component.html",
  styleUrls: ["./upload-folders.component.css"],
})
export class UploadFoldersComponent implements OnInit {
  formData: FormData;
  uploadedPercentage: any = 0;
  tempPercentage: any = 0;
  startProgress: any = 0;
  progress: any = 0;
  length: any = 0;
  files: any[] = [];
  complete: boolean = false;
  uploadInput: EventEmitter<UploadInput>;
  @Output() valueChange = new EventEmitter();
  humanizeBytes: Function;
  dragOver: boolean;
  msg: string;
  options: UploaderOptions;
  token: any;
  folder_id: number = 0;
  dataroomId: string;
  baseUrl: string = "";
  start_upload: boolean = false;
  constructor(
    private dataRoomService: DataRoomService,
    private sharedService: SharedService,
    private toastr: ToastrService,
    private http: HttpClient,
    private baseUrlClass: BaseUrlClass,
    private apiListClass: ApiListClass,
    public dialog: MatDialog
  ) {
    this.dataroomId = localStorage.getItem("currentDataroomId");
    this.baseUrl = this.baseUrlClass.baseUrl;
    this.token = "token " + localStorage.getItem("token");
  }

  ngOnInit() {}

  startUpload(): void {
    const formData = new FormData();

    var i;
    for (i = 0; i < this.file.length; i++) {
      formData.append("file", this.file[i]);
      // formData.append('path', droppedFile.relativePath)
      formData.append("folder", "No");
      formData.append("dataroomId", this.dataroomId);
      console.log(formData);
      if (this.file.length == i + 1) {
        //   this.dataRoomService.uploadFiles(formData, this.folder_id, this.notify)
        //   .subscribe((res)=>{
        //     this.sharedService.sendMessage('Refresh Documents!', 0);
        //     // this.spinner.hide();
        //     // this.msg = res.message//"Upload file successfully !";
        //     // this.showSuccess();
        //     this.msg = "File successfully uploaded !";//res.message//"Upload file successfully !";
        //     this.showSuccess();
        // })
      }
    }
  }

  file: any;
  onUploadOutput(event) {
    this.file = event;
  }

  notify: any = "No";
  NotifyAllMembers() {
    // this.spinner.show();

    this.notify = "Yes";
    this.startUpload();
    // this.router.navigate(['/documents']);
  }

  DontNotifyAllMembers() {
    // this.spinner.show();

    this.notify = "No";
    // this.sharedService.sendMessage('Refresh Folder Details!');
    this.startUpload();
    // this.router.navigate(['/documents']);
  }

  display = "none";

  cancelUpload(id: string): void {
    this.uploadInput.emit({ type: "cancel", id: id });
  }

  removeFile(id: string): void {
    this.uploadInput.emit({ type: "remove", id: id });
  }

  removeAllFiles(): void {
    this.uploadInput.emit({ type: "removeAll" });
  }

  showSuccess() {
    this.toastr.success(this.msg);
  }
  showNote() {
    this.toastr.info(this.note);
  }

  showError() {
    this.toastr.error(this.msg);
  }

  upload_start(files) {
    this.totalCount = 1;

    if (files.length > this.totalCount) {
      this.timeInterval = setInterval(
        () => this.manageProgress(files),
        this.interval
      );
    }
  }
  timeInterval: any;
  incr = 1;
  totalCount = 0;
  interval = 50;
  manageProgress(files) {
    if (this.progress === 100) {
      if (files.length > this.totalCount) {
        this.progress = 0;
        this.totalCount += 1;
      } else {
        clearInterval(this.timeInterval);
      }
    } else {
      this.progress = this.progress + this.incr;
      if (this.totalCount == files.length && this.progress == 75) {
        console.log(this.progress, this.totalCount, files.length);
        this.progress = 100;
        clearInterval(this.timeInterval);
      } else {
        console.log(this.progress);
        files[this.totalCount - 1]["progress"] = this.progress;
      }
    }
  }

  showInfo() {
    this.toastr.info(this.msg);
  }
  modal_action: boolean = false;
  openDialog(event): void {
    const dialogRef = this.dialog.open(UploadConfirmationPopup_1, {
      width: "500px",
      data: { yes: true, no: false },
    });

    dialogRef.afterClosed().subscribe((result) => {
      if (result && result != undefined) {
        this.modal_action = true;
        if (result == true) {
          this.notify = "Yes";
          console.log(result);
          this.dropped(event);
        }
      }
      if (!result && result != undefined) {
        this.modal_action = true;
        console.log(result);
        this.notify = "No";
        this.dropped(event);
      }
    });
  }
  note: any;
  dropped(event: UploadEvent) {
    if (event["files"][0]["relativePath"].indexOf("/") != -1) {
      if (!this.modal_action) {
        this.openDialog(event);
      }
    } else {
      this.msg = "Files cannot be upload from here";
      this.showInfo();
    }

    if (this.modal_action) {
      this.files = event.files;
      event.files.map(function (obj) {
        obj["progress"] = 0;
      });

      const formData = new FormData();
      event.files.forEach((droppedFile, index) => {
        // Is it a file?
        if (droppedFile.fileEntry.isFile) {
          const fileEntry = droppedFile.fileEntry as FileSystemFileEntry;
          fileEntry.file((file: File) => {
            this.length = event.files.length;
            // Here you can access the real file

            if (droppedFile.relativePath.indexOf("/") >= 0) {
              var folder_path = "Yes";
            } else {
              var folder_path = "No";
            }

            formData.append("file", file);
            formData.append("path", droppedFile.relativePath);
            formData.append("folder", folder_path);
            formData.append("dataroomId", this.dataroomId);

            if (folder_path == "Yes") {
              if (event.files.length == index + 1) {
                //   const req = new HttpRequest('POST', this.baseUrl+this.apiListClass.upload_file_inside_folder+this.folder_id+"/?notify="+this.notify, formData, {
                //   headers: new HttpHeaders().set('Authorization', this.token),  reportProgress: true,
                //   });

                //   this.http.request(req).subscribe(event => {
                //   // Via this API, you get access to the raw event stream.
                //   // Look for upload progress events.
                //
                //   if (event.type === HttpEventType.UploadProgress) {
                //     // This is an upload progress event. Compute and show the % done:
                //     this.files[index].index = Math.round(100 * event.loaded / event.total);
                //     console.log(this.files[index].index);
                //   } else if (event instanceof HttpResponse) {
                //     console.log('File is completely uploaded!');
                //   }
                // })

                this.http
                  .post(
                    this.baseUrl +
                      this.apiListClass.upload_file_inside_folder +
                      this.folder_id +
                      "/?notify=" +
                      this.notify,
                    formData,
                    {
                      headers: new HttpHeaders().set(
                        "Authorization",
                        this.token
                      ),
                      responseType: "blob",
                      reportProgress: true,
                      observe: "events",
                    }
                  )
                  .subscribe(
                    (events: HttpEvent<any>) => {
                      switch (events.type) {
                        case HttpEventType.Sent:
                          this.start_upload = true;
                          this.note =
                            "Please do not leave or refresh this page while the files are being uploaded. You will get a notification once the files are successfully uploaded on the data room.. File uploading time will depend on the data size & your uploading speed. If you need any help, please write to support@docullyvdr.com";
                          this.showNote();

                          this.upload_start(this.files);
                          this.sharedService.stopLoader();
                          console.log("Start");
                          break;
                        case HttpEventType.Response:
                          console.log("Success");
                          this.interval = 1;
                          this.modal_action = false;
                          event.files[index]["progress"] = 100;

                          this.msg =
                            "Files uploaded successfully. For more info refer to Upload Status section on the Documents tab. "; //res.message//"Upload file successfully !";
                          this.showSuccess();

                          setTimeout(
                            () =>
                              this.sharedService.sendMessage(
                                "Refresh Folder Details!",
                                0
                              ),
                            200
                          );
                          break;
                        case HttpEventType.UploadProgress:
                          break;
                      }
                    },
                    (error) => {
                      console.log(error);
                    }
                  );

                //   this.dataRoomService.uploadFiles(formData, this.folder_id, this.notify)
                //   .subscribe((res)=>{
                //     console.log(4545);
                //     console.log(event);
                //     this.sharedService.sendMessage('Refresh Documents!', 0);
                //     this.msg = "File successfully uploaded !";//res.message//"Upload file successfully !";
                //     this.showSuccess();
                // })

                // console.log(this.uploadedPercentage);
              }
            } else {
              // It was a directory (empty directories are added, otherwise only files)
              this.msg = "Files cannot be upload from here";
              this.showInfo();
            }
          });
        } else {
          // It was a directory (empty directories are added, otherwise only files)
          this.msg = "Files cannot be upload from here";
          this.showInfo();
        }
      });
    }
  }

  public fileOver(event) {
    console.log(event);
  }

  public fileLeave(event) {
    console.log(event);
  }
}

