import { Component, OnInit, Input, Output, EventEmitter } from '@angular/core';
import { Validators, FormGroup, FormControl, FormArray, FormBuilder, NgForm } from '@angular/forms';
import { DataRoomService, SharedService } from '../../../services/index';
import { ToastrService } from 'ngx-toastr';
import { RouterModule, Routes } from '@angular/router';
import { Router, ActivatedRoute, ParamMap } from '@angular/router';
import { Subscription } from 'rxjs';
import { BaseUrlClass, ApiListClass } from '../../../common/index';
import { TimezoneService } from '../../../services/timezone.service';
declare var jQuery:any;

@Component({
  selector: 'app-datarooms',
  templateUrl: './datarooms.component.html',
  styleUrls: ['./datarooms.component.css']
})
export class DataroomsComponent implements OnInit {
  datarooms:any

  is_dataroom_exist:boolean = false;
	@Input() my_team_id : any;
  	public createNewDataroomForm: FormGroup; // our form model
    msg : any;
  	errors : any;
    timezone:any;
  	areControlsEnabled : boolean = false;
    message: any;
    subscription: Subscription;
    filterQuery:any;
 	//my_team_id : number ;
  constructor(private dataRoomService: DataRoomService, 
    private toastrService : ToastrService, 
    private router : Router, 
    private sharedService: SharedService,
    private route: ActivatedRoute,
    private timeZone:TimezoneService
    ) {
      this.subscription = this.sharedService.getMessage().subscribe(message => { 
      
      this.message = message; 
      this.my_team_id = this.message.id;
      if(this.message.text == 'Refresh Dataroom!'){
        this.my_team_id = this.message.id;
        this.get_all_my_team_members();
        this.get_my_team_data();
        this.createNewDataroom();
        this.timezone = this.timeZone.userTimeZone;
    }
  })
     }

  ngOnInit() {
  	
  	this.get_all_my_team_members();
  	this.get_my_team_data();
  	this.createNewDataroom();

  }
  numericNumberReg:any='^[0-9]\\d*(\\.\\d{1,2})?$';


  createNewDataroom(){
  this.createNewDataroomForm = new FormGroup({
      dataroom_name: new FormControl('', [
          Validators.minLength(3),
          Validators.maxLength(40),
          Validators.required
      ]),

  		dataroom_modules: new FormGroup({ 
  		        is_watermarking : new FormControl(!this.areControlsEnabled, []), 
  		        is_drm : new FormControl(!this.areControlsEnabled, []), 
  		        is_question_and_answers : new FormControl(!this.areControlsEnabled, []), 
  		        is_collabration : new FormControl(!this.areControlsEnabled, []), 
  		        is_ocr : new FormControl(!this.areControlsEnabled, []), 
  		        is_editor : new FormControl(!this.areControlsEnabled, []),  
  		}), 

      is_account_level_branding : new FormControl(!this.areControlsEnabled, []), 
      dataroom_id : new FormControl('', [Validators.required]),
      dataroom_storage_allocated : new FormControl('', [Validators.minLength(1), Validators.maxLength(4), Validators.required,Validators.pattern(this.numericNumberReg)]),
      dataroom_admin : new FormGroup({
        first_name : new FormControl('', [Validators.minLength(3), Validators.maxLength(40), Validators.required]), 
        last_name : new FormControl('', [Validators.minLength(3), Validators.maxLength(40), Validators.required]), 
        email : new FormControl('', [Validators.minLength(3), Validators.maxLength(40), Validators.required,Validators.pattern(/^(([^<>()[\]\\.,;:\s@\"]+(\.[^<>()[\]\\.,;:\s@\"]+)*)|(\".+\"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/)]), 
      }),
       
    });
  }

  // submit new dataroom 

  submitNewDataroom(new_dataroom : any){
  	console.log("New dataroom form", new_dataroom, this.my_team_id);
  	this.dataRoomService.create_dataroom_from_my_team(this.my_team_id, new_dataroom)
  	.subscribe((res)=>{
  		console.log("Dataroom successfully cretaed");
  		if(res.success===true){
  			console.log("Success is true");
  			this.msg = res.message;
  			this.showSuccess();
  			this.all_datarooms.push(res.data);
  			this.createNewDataroom();
        jQuery("#addDateRoom").modal("hide");
        // window.location.reload();
  		}else{
  			this.msg = res.message;
  			this.showError();
  			console.log("Error is false");
  		}
  	})
  }


  // get all datarooms 

	all_datarooms: any ;
	all_members : any;
	my_team_data : any;
	get_all_my_team_members(){
	this.dataRoomService.get_all_my_team_members(this.my_team_id)
		.subscribe((res)=>{
			
			this.all_datarooms = res.datarooms;
			this.all_members = res.all_members;
		})
	}


   showSuccess(){
    	this.toastrService.success( this.msg);
    }


    showError(){
    	this.toastrService.error( this.msg);
    }

 get_my_team_data(){
  	  this.dataRoomService.getMyTeamData(this.my_team_id).subscribe((res)=>{
      //res.my_team_logo  = this.base_url+res.my_team_logo;                  
      this.my_team_data = res;
      console.log("my team data is", this.my_team_data);
    })
  }

}
