import { Component, OnInit } from '@angular/core';
import { DataRoomService } from '../../../services/dataroom_service'
import * as moment from 'moment';
import { TimezoneService } from '../../../services/timezone.service';

@Component({
  selector: 'app-users-and-groups',
  templateUrl: './users-and-groups.component.html',
  styleUrls: ['./users-and-groups.component.css']
})
export class UsersAndGroupsComponent implements OnInit {
group: any = 0;
removed: boolean = false;
   timezone:any;
dataroomId : any;
  constructor(private dataRoomService: DataRoomService,private timeZone:TimezoneService) {
  	this.dataroomId = (localStorage.getItem("currentDataroomId")).toString();
    this.getSingleDataroom(this.dataroomId);
    this.timezone = this.timeZone.userTimeZone;
   }

  ngOnInit() {
  	this.getAllGroups();
  }


  groups:any ;
  getAllGroups(){
    this.dataRoomService.getAllGroups(this.dataroomId)
    .subscribe((res)=>{
        this.groups = res;
        
        this.getUsersMember();
    })
  }


groupType(event){
	this.group = event;
	this.getUsersMember();
}

RemovedMembers(event){
	this.removed = event;
	this.getUsersMember();
}
users: any;
getUsersMember(){
	this.dataRoomService.GetUserGroups(this.group, this.dataroomId, this.removed)
	.subscribe((res)=>{
		this.users = res.users;
		
	})
}

ExportUsersGroups(){
	this.dataRoomService.ExportUsersGroups(this.group, this.dataroomId, this.removed, this.dataroom_name, this.current_date)
	.subscribe((res)=>{
		
	})
}


  dataroom_detail:any;
current_date:any;
dataroom_name:any;
  getSingleDataroom(dataroomId){
  this.dataRoomService.getSingleDataroom(dataroomId)
    .subscribe((res)=>{
      this.dataroom_detail = res;
      this.dataroom_name = res.dataroom_name;
      // this.avatarUrl = this._base_url+this.dataroom_detail.dataroom_admin_data.member.avatar;
      // this.avatarUrl = this.avatarUrl.replace("//media/", "/media/");
      // this.avatarUrl = 'assets/images/avatar-not.png';
      let todays_date = new Date();
      this.current_date = moment(todays_date).format('YYYY-MM-DD hh-mm-ss a');
              
      })  
  }


}
