import { Component, OnInit } from "@angular/core";
import { DataRoomService } from "../../../services/dataroom_service";
import { Chart } from "angular-highcharts";
import { BaseUrlClass, ApiListClass } from "../../../common/index";
import { MatProgressSpinnerModule } from "@angular/material/progress-spinner";
import * as moment from "moment";
import { TimezoneService } from "../../../services/timezone.service";

@Component({
  selector: "app-report-overview",
  templateUrl: "./report-overview.component.html",
  styleUrls: ["./report-overview.component.css"],
})
export class ReportOverviewComponent implements OnInit {
  from_date: any;
  to_date: any;
  dataroomId: any;
  timezone: any;
  moment: any = moment;
  baseUrl: any;
  p: number = 1;
  show_spinner: boolean = true;
  constructor(
    private dataRoomService: DataRoomService,
    public baseUrlclass: BaseUrlClass,
    private timeZone: TimezoneService
  ) {
    this.dataroomId = localStorage.getItem("currentDataroomId").toString();
    this.getSingleDataroom(this.dataroomId);
    this.baseUrl = this.baseUrlclass.baseUrl;
    this.timezone = this.timeZone.userTimeZone;
  }

  // dataroom_notification: any;
  // getSingleDataroomNotification(){
  // this.dataRoomService.getSingleDataroomNotificationList(this.dataroomId, 'All')
  //   .subscribe((res)=>{

  //     this.dataroom_notification = res.data.reverse();;
  //   })
  // }

  charts: any;
  ngOnInit() {
    this.show_spinner = true;
    this.getDateWise();
    this.getUserInfo();
    this.getAllDisclaimers();
    this.getActivityUser();
  }

  activity: any;
  getActivityUser() {
    var todays =
      this.to_date.getFullYear() +
      "-" +
      (this.to_date.getMonth() + 1) +
      "-" +
      this.to_date.getDate();
    var first =
      this.from_date.getFullYear() +
      "-" +
      (this.from_date.getMonth() + 1) +
      "-" +
      this.from_date.getDate();
    console.log("Todays Date Overview", todays);
    console.log("First Date Overview", first);

    this.dataRoomService
      .getActivityDataroom(this.dataroomId, first, todays)
      .subscribe((res) => {
        this.activity = res;
        //console.log(res.created_date, "Created Date");

        // for (var i = 0; i < this.activity.length; i++) {
        //   this.activity1.push(
        //     moment(this.activity[i].created_date).format("YYYY-MM-DD HH:mm")
        //   );
        // }
        // this.activity2 = this.activity1.slice();

        console.log(this.activity, "User Overview");

        this.show_spinner = false;
      });
  }

  all_disclaimers: boolean = false;
  getAllDisclaimers() {
    this.dataRoomService.getAllDisclaimers(this.dataroomId).subscribe((res) => {
      var disclaimers = res.filter(
        (res) => res.is_dataroom_disclaimer_default === true
      );

      if (disclaimers.length > 0) {
        this.all_disclaimers = false;
      } else {
        this.all_disclaimers = true;
      }
    });
  }

  user: any;
  user_id: number;
  getUserInfo() {
    this.dataRoomService
      .getUserProfileDatroom(this.dataroomId)
      .subscribe((res) => {
        this.user = res;
        this.user_id = res.id;
        this.getDataroomUser();
      });
  }

  primary_users_disclaimer_status: any;
  getDataroomUser() {
    this.dataRoomService
      .dataroom_mem_list(this.dataroomId, this.user_id)
      .subscribe((res) => {
        this.primary_users_disclaimer_status = res[0];
      });
  }

  curr: any;
  getDateWise() {
    this.curr = new Date(); // get current date
    this.from_date = this.curr.getDate() - this.curr.getDay(); // First day is the day of the month - the day of the week

    console.log("getdate======>", this.curr.getDate());
    console.log("getDay======>", this.curr.getDay());
    this.to_date = this.from_date + 6; // last day is the first day + 6
    this.from_date = new Date(
      this.curr.getFullYear(),
      this.curr.getMonth() - 1,
      this.curr.getDate()
    );
    this.to_date = new Date(
      this.curr.getFullYear(),
      this.curr.getMonth(),
      this.curr.getDate()
    );
    console.log("ravi=====>", this.from_date);

    this.getCharts();
  }

  data: any;
  getCharts() {
    var todays = new Date(
      this.to_date.getFullYear() +
        "-" +
        ("0" + (this.to_date.getMonth() + 1)).slice(-2) +
        "-" +
        ("0" + this.to_date.getDate()).slice(-2)
    );
    var first = new Date(
      this.from_date.getFullYear() +
        "-" +
        ("0" + (this.from_date.getMonth() + 1)).slice(-2) +
        "-" +
        ("0" + this.from_date.getDate()).slice(-2)
    );

    this.dataRoomService
      .GetBarchartDataroomView(this.dataroomId, first, todays)
      .subscribe((res) => {
        this.data = res;

        this.getBarChart();
      });
  }
  changeDateWise(from_date, to_date) {
    this.from_date = from_date;
    this.to_date = to_date;
    this.getActivityUser();
    this.getCharts();
  }

  getBarChart() {
    this.charts = new Chart({
      chart: {
        type: "column",
      },
      title: {
        text: "Dataroom Views",
      },
      credits: {
        enabled: false,
      },
      xAxis: {
        categories: this.data.dates_list,
        crosshair: true,
      },
      yAxis: {
        min: 0,
        title: {
          text: "Counts",
        },
      },
      tooltip: {
        headerFormat: '<span style="font-size:10px">{point.key}</span><table>',
        pointFormat:
          '<tr><td style="color:{series.color};padding:0">{series.name}: </td>' +
          '<td style="padding:0"><b>{point.y:.1f}</b></td></tr>',
        footerFormat: "</table>",
        shared: true,
        useHTML: true,
      },
      plotOptions: {
        column: {
          pointPadding: 0.2,
          borderWidth: 0,
        },
      },
      series: [
        {
          name: "Views",
          data: this.data.dataroom_views,
        },
      ],
    });
  }

  ExportOverview() {
    var todays =
      this.to_date.getFullYear() +
      "-" +
      (this.to_date.getMonth() + 1) +
      "-" +
      this.to_date.getDate();
    var first =
      this.from_date.getFullYear() +
      "-" +
      (this.from_date.getMonth() + 1) +
      "-" +
      this.from_date.getDate();

    this.dataRoomService
      .ExportOverviewReport(
        this.dataroomId,
        this.dataroom_name,
        this.current_date,
        first,
        todays
      )
      .subscribe((res) => {
        console.log("Export Overview Successfully");
      });
  }

  goToViewerPage(folder) {
    console.log("folder id is", folder);
    this.dataRoomService.getFilesUpdated(folder.id, "view").subscribe((res) => {
      let token = localStorage.getItem("token");
      document.cookie = "token=" + token;
      // window.open(url, '_blank');
      // href="{{baseUrl}}/file-view/{{folder.id}}/{{user.id}}/" target="_blank"
      // this.router.navigate(['/file-views', folder.dataroom_folder_uuid]);
    });
  }

  dataroom_detail: any;
  current_date: any;
  dataroom_name: any;
  getSingleDataroom(dataroomId) {
    this.dataRoomService.getSingleDataroom(dataroomId).subscribe((res) => {
      this.dataroom_detail = res;
      this.dataroom_name = res.dataroom_name;
      // this.avatarUrl = this._base_url+this.dataroom_detail.dataroom_admin_data.member.avatar;
      // this.avatarUrl = this.avatarUrl.replace("//media/", "/media/");
      // this.avatarUrl = 'assets/images/avatar-not.png';
      let todays_date = new Date();
      this.current_date = moment(todays_date).format("YYYY-MM-DD hh-mm-ss a");
    });
  }
}
