import { Component, OnInit } from "@angular/core";
import { DataRoomService } from "../../services/index";
import { ToastrService } from "ngx-toastr";
import { BaseUrlClass, ApiListClass } from "../../common/index";
import {
  FormBuilder,
  FormGroup,
  FormArray,
  FormControl,
  Validators,
} from "@angular/forms";
import { Location } from "@angular/common";
import { TimezoneService } from "../../services/timezone.service";

@Component({
  selector: "app-faq",
  templateUrl: "./faq.component.html",
  styleUrls: ["./faq.component.css"],
})
export class FaqComponent implements OnInit {
  dataroomId: any;
  msg: string = "";
  baseUrl: any = "";
  timezone: any;
  deleteForm: FormGroup;
  faqForm: any;
  question_data: any = {
    id: null,
    question: "",
    answer: "",
    qna: "",
    folder: { id: null },
  };

  constructor(
    private dataRoomService: DataRoomService,
    private toastr: ToastrService,
    private timeZone: TimezoneService,
    public baseUrlclass: BaseUrlClass,
    private _location: Location
  ) {
    this.dataroomId = localStorage.getItem("currentDataroomId");
    this.baseUrl = this.baseUrlclass.baseUrl;
    this.timezone = this.timeZone.userTimeZone;
  }

  ngOnInit() {
    this.getAllFAQ(false);
    this.getUserInfo();
    this.initializeDeleteForm();
    this.faqForm = new FormGroup({
      question: new FormControl("", [
        Validators.required,
        Validators.minLength(1),
      ]),
      answer: new FormControl("", [
        Validators.required,
        Validators.minLength(1),
      ]),
    });
  }

  initializeDeleteForm() {
    this.deleteForm = new FormGroup({
      delete: new FormControl("", [
        Validators.required,
        Validators.minLength(6),
        Validators.maxLength(6),
      ]),
    });
  }

  goToViewerPage(folder) {
    console.log("folder id is", folder);
    let token = localStorage.getItem("token");
    document.cookie = "token=" + token;
    this.dataRoomService.getFilesUpdated(folder.id, "view").subscribe((res) => {
      let token = localStorage.getItem("token");
      document.cookie = "token=" + token;
      // window.open(url, '_blank');
      // href="{{baseUrl}}/file-view/{{folder.id}}/{{user.id}}/" target="_blank"
      // this.router.navigate(['/file-views', folder.dataroom_folder_uuid]);
    });
  }

  user: any;
  user_id: number;
  getUserInfo() {
    this.dataRoomService
      .getUserProfileDatroom(this.dataroomId)
      .subscribe((res) => {
        this.user = res;
        this.user_id = res.id;
        this.getDataroomUser();
      });
  }

  data: any = [];
  show_faq: boolean = false;

  getAllFAQ(is_faq) {
    this.show_faq = true;

    if (is_faq) {
      this.show_faq = false;
    }

    this.dataRoomService.GetFaq(this.dataroomId).subscribe((res) => {
      this.data = res;
      console.log(res, "Faq test");
    });
  }

  AddToFaq(item) {
    console.log(item);
    if (item.answer === "" || item.question === "") {
      this.msg = "Please add a question and an answer and then submit.";
      this.showError();
      return 0;
    }
    item["dataroom"] = this.dataroomId;
    item["user"] = this.user;
    this.dataRoomService.postRequest(item, this.dataroomId).subscribe((res) => {
      console.log(res);
      this.data = res;
      this.msg = "FAQ question updated successfully !";
      this.showSuccess();
    });
  }

  deleteFaq(item) {
    console.log(item);
    item.status = false;
    this.dataRoomService.postRequest(item, this.dataroomId).subscribe((res) => {
      console.log(res);
      this.data = res;
      this.msg = "FAQ question updated successfully !";
      this.showSuccess();
    });
  }

  data1: any[] = [];

  update: any[] = [];

  showSuccess() {
    this.toastr.success(this.msg);
  }

  showError() {
    this.toastr.error(this.msg);
  }

  showInfo() {
    this.toastr.info(this.msg);
  }

  primary_users_disclaimer_status: any;
  getDataroomUser() {
    this.dataRoomService
      .dataroom_mem_list(this.dataroomId, this.user_id)
      .subscribe((res) => {
        this.primary_users_disclaimer_status = res[0];
      });
  }
  geBack() {
    this._location.back();
  }
}
