import { Component, OnInit } from "@angular/core";
import { DataRoomService } from "../../../services/dataroom_service";
import * as moment from "moment";
import { TimezoneService } from "../../../services/timezone.service";
@Component({
  selector: "app-active-by-files",
  templateUrl: "./active-by-files.component.html",
  styleUrls: ["./active-by-files.component.css"],
})
export class ActiveByFilesComponent implements OnInit {
  from_date: any;
  to_date: any;
  dataroomId: any;
  moment: any = moment;
  timezone: any;
  filterQuery: any;
  p: number = 1;
  constructor(
    private dataRoomService: DataRoomService,
    private timeZone: TimezoneService
  ) {
    this.dataroomId = localStorage.getItem("currentDataroomId").toString();
    this.getSingleDataroom(this.dataroomId);
    this.timezone = this.timeZone.userTimeZone;
  }

  ngOnInit() {
    this.getDateWise();
  }
  dataroom_detail: any;
  current_date: any;
  dataroom_name: any;
  size: number = 0;
  getSingleDataroom(dataroomId) {
    this.dataRoomService.getSingleDataroom(dataroomId).subscribe((res) => {
      this.dataroom_detail = res;
      this.dataroom_name = res.dataroom_name;
      // this.avatarUrl = this._base_url+this.dataroom_detail.dataroom_admin_data.member.avatar;
      // this.avatarUrl = this.avatarUrl.replace("//media/", "/media/");
      // this.avatarUrl = 'assets/images/avatar-not.png';
      let todays_date = new Date();
      this.current_date = moment(todays_date).format("YYYY-MM-DD hh-mm-ss");
    });
  }

  deleted_files: boolean = false;
  getDateWise() {
    var today = new Date();
    this.to_date = new Date(
      today.getFullYear(),
      today.getMonth(),
      today.getDate()
    );
    this.from_date = new Date(
      today.getFullYear(),
      today.getMonth() - 1,
      today.getDate()
    );
    this.GetActivityByDate(this.p);
  }

  data: any;
  GetActivityByDate(pagenumber) {
    this.p = pagenumber;
    var todays =
      this.to_date.getFullYear() +
      "-" +
      (this.to_date.getMonth() + 1) +
      "-" +
      this.to_date.getDate();
    var first =
      this.from_date.getFullYear() +
      "-" +
      (this.from_date.getMonth() + 1) +
      "-" +
      this.from_date.getDate();
    this.dataRoomService
      .GetActivityByFile(
        first,
        todays,
        this.deleted_files + "&page=" + pagenumber,
        this.dataroomId
      )
      .subscribe((res) => {
        this.data = res.data;
        this.size = res.size;
        console.log("this.data ", res);
      });
  }

  changeDateWise(from_date, to_date) {
    this.to_date = to_date;
    this.from_date = from_date;
    this.GetActivityByDate(this.p);
  }

  RemovedMembers(event) {
    this.deleted_files = event;
    this.GetActivityByDate(this.p);
  }

  ExportActivity(from_date, to_date) {
    var todays =
      to_date.getFullYear() +
      "-" +
      (to_date.getMonth() + 1) +
      "-" +
      to_date.getDate();
    var first =
      from_date.getFullYear() +
      "-" +
      (from_date.getMonth() + 1) +
      "-" +
      from_date.getDate();

    this.dataRoomService
      .getActivityByFileExcel(
        this.dataroomId,
        first,
        todays,
        this.deleted_files,
        this.dataroom_name,
        this.current_date
      )
      .subscribe((res) => {
        console.log("Excel data", res.data);
      });
  }
}
