import { Component, OnInit } from '@angular/core';
import { DataRoomService } from '../../../services/dataroom_service';
import { ToastrService } from 'ngx-toastr';
import * as moment from 'moment';
import { TimezoneService } from '../../../services/timezone.service';
@Component({
  selector: 'app-users-status',
  templateUrl: './users-status.component.html',
  styleUrls: ['./users-status.component.css']
})
export class UsersStatusComponent implements OnInit {

  dataroomId : any;
  timezone:any;
  constructor(private dataRoomService: DataRoomService,
              private toastr: ToastrService, private timeZone:TimezoneService) { 
  	this.dataroomId = (localStorage.getItem("currentDataroomId")).toString();
    this.getSingleDataroom(this.dataroomId);
    this.timezone = this.timeZone.userTimeZone;
  }


  ngOnInit() {
  	this.getDateWise();
    this.getAllGroups();

  }

from_date:any;
to_date:any;
getDateWise(){
  var today = new Date();
  this.to_date = new Date(today.getFullYear(), today.getMonth(), today.getDate());
  this.from_date = new Date(2017, 1, 1);
  this.GetUsersStatus();
}

data:any;
  GetUsersStatus(){
    var todays = this.to_date.getFullYear()+'-'+(this.to_date.getMonth()+1)+'-'+this.to_date.getDate();
    var first = this.from_date.getFullYear()+'-'+(this.from_date.getMonth()+1)+'-'+this.from_date.getDate();

	this.dataRoomService.GetUsersStatus(this.dataroomId, first, todays, this.group)
		.subscribe((res)=>{
			
			this.data = res;
			console.log("this.data ", this.data);
	})
	}

changeDateWise(from_date, to_date){
    this.to_date = to_date;
    this.from_date = from_date;
    this.GetUsersStatus();
  }


groups:any;
  getAllGroups(){
    this.dataRoomService.getAllGroups(this.dataroomId)
    .subscribe((res)=>{
        this.groups = res;
        
    })
  }

group:any = 0;
groupType(value){
   this.group = value;
   this.GetUsersStatus();
}

showSuccess(){
    this.toastr.success( this.msg);
  }


  showError(){
    this.toastr.error( this.msg);
  }

  showInfo(){
    this.toastr.info( this.msg);
  }

msg:any;
  removeSelectedElement(member, i){
  console.log("delete admin", member);
    this.dataRoomService.delete_dataroom_admin(member.id)
    .subscribe((res=>{
    // this.data.splice(i, 1);
    this.msg = "Removed Member Successfully !";
    this.showError();
    this.GetUsersStatus();
    }))
}

ExportUsersStatus(from_date, to_date){
    var todays = to_date.getFullYear()+'-'+(to_date.getMonth()+1)+'-'+to_date.getDate();
    var first = from_date.getFullYear()+'-'+(from_date.getMonth()+1)+'-'+from_date.getDate();

    this.dataRoomService.ExportUsersStatus(this.dataroomId, first, todays, this.dataroom_name, this.current_date)
    .subscribe((res)=>{
      
    })

  }

  dataroom_detail:any;
current_date:any;
dataroom_name:any;
  getSingleDataroom(dataroomId){
  this.dataRoomService.getSingleDataroom(dataroomId)
    .subscribe((res)=>{
      this.dataroom_detail = res;
      this.dataroom_name = res.dataroom_name;
      // this.avatarUrl = this._base_url+this.dataroom_detail.dataroom_admin_data.member.avatar;
      // this.avatarUrl = this.avatarUrl.replace("//media/", "/media/");
      // this.avatarUrl = 'assets/images/avatar-not.png';
      let todays_date = new Date();
      this.current_date = moment(todays_date).format('YYYY-MM-DD hh-mm-ss a');
              
      })  
  }

}
