import {
  Component,
  OnInit,
  ViewEncapsulation,
  Input,
  Output,
} from "@angular/core";
import { FormGroup, FormControl, Validators } from "@angular/forms";
import { ToastrService } from "ngx-toastr";
import { DataRoomService } from "../../services/index";
import { Router, ActivatedRoute } from "@angular/router";
import { TimezoneService } from "../../services/timezone.service";
@Component({
  selector: "app-dashboard",
  templateUrl: "./dashboard.component.html",
  styleUrls: ["./dashboard.component.css"],
})
export class DashboardComponent implements OnInit {
  config: any;
  msg: any;
  errors: any;
  timezone: any;
  createNewDataroomForm: FormGroup;
  areControlsEnabled: boolean = true;
  dataroomId: number;
  filterQuery: any;
  foods = [
    { value: "steak-0", viewValue: "Steak" },
    { value: "pizza-1", viewValue: "Pizza" },
    { value: "tacos-2", viewValue: "Tacos" },
  ];

  constructor(
    private dataRoomService: DataRoomService,
    private toastr: ToastrService,
    private router: Router,
    private route: ActivatedRoute,
    private timeZone: TimezoneService
  ) {
    this.route.params.subscribe((params) => {
      console.log("dataroom id is");
      this.dataroomId = params.dataroomId;
      console.log(params.dataroomId);
      this.timezone = this.timeZone.userTimeZone;
    }); // Object {}
  }

  user: any;
  ngOnInit() {
    this.getUserInfo();

    this.createNewDataroom();
    this.getAllDataRoomsFolders();
  }

  getUserInfo() {
    this.dataRoomService.getUserProfile().subscribe((res) => {
      //
      this.user = res;
      this.getAllDataRooms();
      //localStorage.setItem('currentUser',  JSON.stringify(res));
    });
  }

  datarooms: any;
  is_admin: boolean = false;
  getAllDataRooms() {
    this.dataRoomService.getAllDatarooms().subscribe((res) => {
      this.datarooms = res;
      console.log(res, "Flag Room");

      if (this.user.is_superadmin == true || this.user.is_admin == true) {
        this.is_admin = true;
        this.datarooms.forEach((res) => {
          res.selected = true;
        });
      } else {
        //this.choose_overview_default_page = res.choose_overview_default_page;

        this.datarooms.forEach((res) => {
          if (res.member.is_la_user) {
            res.selected = true;
          } else {
            if (res.is_dataroom_on_live == true) {
              res.selected = true;
            } else {
              res.selected = false;
            }
          }
        });
      }

      this.datarooms = this.datarooms.filter((res) => res.selected === true);

      this.datarooms.forEach((res) => {
        if (!res.is_paid) {
          let todays_date = new Date();
          console.log("todays_date Date", todays_date);
          console.log("Date", res.created_date);
          var date = new Date(res.created_date);
          console.log("Date", date);
          var timeDiff = Math.abs(todays_date.getTime() - date.getTime());
          console.log("timeDiff Date", timeDiff);
          var diff_date = Math.ceil(timeDiff / (1000 * 3600 * 24));
          console.log("Difference Date", diff_date);
          if (diff_date <= res.trial_days) {
            let rem_date = 16 - diff_date;
            res.upgrade_msg = "trial expires in " + rem_date + " days";
          } else {
            res.upgrade_msg = "extended trial";
          }
        } else {
          res.upgrade_msg = "";
        }
      });
    });
  }

  folders: any;
  getAllDataRoomsFolders() {
    this.dataRoomService.getAllDataRoomsFolders().subscribe((res) => {
      //
      this.folders = res;
    });
  }
  dataroom: any;
  datarooms_folders: any;
  selectDataroom(dataroomId) {
    this.datarooms_folders = this.folders.filter(
      (res) => res.dataroom == parseInt(dataroomId)
    );
    this.dataRoomService.getSingleDataroom(dataroomId).subscribe((res) => {
      this.update.is_watermarking = res.dataroom_modules.is_watermarking;
      this.update.is_drm = res.dataroom_modules.is_drm;
      this.update.is_question_and_answers =
        res.dataroom_modules.is_question_and_answers;
      this.update.is_collabration = res.dataroom_modules.is_collabration;
      this.update.is_ocr = res.dataroom_modules.is_ocr;
      this.update.is_editor = res.dataroom_modules.is_editor;
    });
  }

  perm: any;
  gotoURl(dataroomId, dataroomName, choose_overview_default_page) {
    localStorage.setItem("currentDataroomId", dataroomId.toString());
    this.dataRoomService
      .get_dataroom_disclaimer(dataroomId)
      .subscribe((res) => {
        // console.log(res.member.is_end_user, "TRipTest");

        if (res.overview.show_multiple_times_disclaimer == false) {
          if (res.member.disclaimer_status == false) {
            if (res.disclaimer.id == undefined) {
              if (res.member.is_end_user !== undefined) {
                if (res.member.is_end_user === true) {
                  this.getToDetailedPage(
                    dataroomId,
                    res.overview.choose_overview_default_page
                  );
                } else {
                  this.getToDetailedPage(dataroomId, true);
                }
              }
            } else {
              this.router.navigate(["../disclaimer-popup", res.disclaimer.id]);
            }
          } else {
            if (res.member.is_end_user !== undefined) {
              if (res.member.is_end_user === true) {
                this.getToDetailedPage(
                  dataroomId,
                  res.overview.choose_overview_default_page
                );
              } else {
                this.getToDetailedPage(dataroomId, true);
              }
            }
          }
        } else {
          if (res.member.disclaimer_status == false) {
            if (res.disclaimer.id == undefined) {
              this.getToDetailedPage(dataroomId, choose_overview_default_page);
            } else {
              localStorage.setItem(
                "Multiple" + "&" + dataroomName + "&" + dataroomId,
                "true"
              );
              this.router.navigate(["../disclaimer-popup", res.disclaimer.id]);
            }
          } else {
            console.log(res.overview.choose_overview_default_page, "Grtp");
            if (res.member.is_end_user !== undefined) {
              if (res.member.is_end_user === true) {
                this.getToDetailedPage(
                  dataroomId,
                  res.overview.choose_overview_default_page
                );
              } else {
                this.getToDetailedPage(dataroomId, true);
              }
            }
          }
        }
        // this.getToDetailedPage(dataroomId,choose_overview_default_page)
      });
    // this.getToDetailedPage(dataroomId,choose_overview_default_page)
  }

  getToDetailedPage(dataroomId, choose_overview_default_page) {
    this.dataRoomService.getMembersPermission(dataroomId).subscribe((res) => {
      this.perm = res;
      console.log(choose_overview_default_page, "this.perm");
      if (this.perm.is_overview && choose_overview_default_page == true) {
        this.router.navigate(["../overview", dataroomId]);
      } else if (
        this.perm.is_edit_index &&
        choose_overview_default_page == false
      ) {
        this.router.navigate(["../documents"]);
      } else if (choose_overview_default_page == true) {
        this.router.navigate(["../overview", dataroomId]);
      } else if (choose_overview_default_page == false) {
        this.router.navigate(["../documents"]);
      } else if (this.perm.is_edit_index) {
        this.router.navigate(["../documents"]);
      } else if (this.perm.is_users_and_permission) {
        this.router.navigate(["../user-and-permissions"]);
      } else if (this.perm.is_updates) {
        this.router.navigate(["../update-doc"]);
      } else if (this.perm.is_q_and_a) {
        this.router.navigate(["../qa-user"]);
      } else if (this.perm.is_reports) {
        this.router.navigate(["../report-overview"]);
      } else {
        this.router.navigate(["../overview", dataroomId]);
      }

      this.getDataroomViewed(dataroomId);
    });
  }

  getDataroomViewed(dataroomId) {
    this.dataRoomService.GetAllDataroomView(dataroomId).subscribe((res) => {
      console.log("Dataroom Viewed" + dataroomId);
    });
  }

  IsShowHideGride: boolean = false;
  showHideGrideView() {
    this.IsShowHideGride = true;
  }

  showHideListView() {
    this.IsShowHideGride = false;
  }

  createNewDataroom() {
    this.createNewDataroomForm = new FormGroup({
      dataroom_name: new FormControl("", [
        Validators.minLength(3),
        Validators.maxLength(40),
        Validators.required,
      ]),
      dataroom_modules: new FormGroup({
        is_watermarking: new FormControl(!this.areControlsEnabled, []),
        is_drm: new FormControl(!this.areControlsEnabled, []),
        is_question_and_answers: new FormControl(!this.areControlsEnabled, []),
        is_collabration: new FormControl(!this.areControlsEnabled, []),
        is_ocr: new FormControl(!this.areControlsEnabled, []),
        is_editor: new FormControl(!this.areControlsEnabled, []),
      }),

      is_account_level_branding: new FormControl(!this.areControlsEnabled, []),
      dataroom_admin: new FormGroup({
        first_name: new FormControl("", [
          Validators.minLength(3),
          Validators.maxLength(40),
          Validators.required,
        ]),
        last_name: new FormControl("", [
          Validators.minLength(3),
          Validators.maxLength(40),
          Validators.required,
        ]),
        email: new FormControl("", [
          Validators.minLength(3),
          Validators.maxLength(40),
          Validators.required,
        ]),
      }),
      dataroom_storage_allocated: new FormControl("", [
        Validators.minLength(1),
        Validators.required,
        Validators.maxLength(4),
      ]),
    });
  }

  is_dataroom_exist: boolean = false;
  submitNewDataroom(createNewDataroomForm) {
    //
    console.log("submit new dataroom");
    console.log(createNewDataroomForm);
    this.dataRoomService.createDataRoom(createNewDataroomForm).subscribe(
      (res) => {
        console.log("res after cretaion data", res);
        this.is_dataroom_exist = false;
        setTimeout(() => {
          //<<<---    using ()=> syntax
          this.is_dataroom_exist = false;
        }, 3000);
        this.msg = "Dataroom successfully created";
        this.showSuccess();
        console.log("serializer data is ", res);
        this.datarooms.push(res);
        this.createNewDataroom();
      },

      (error) => {
        this.msg = "Internal error occurred !";
        this.is_dataroom_exist = true;
        this.errors = error;
        console.log(error);
        this.showError();
      },

      () => {
        // No errors, route to new page
      }
    );
  }

  showSuccess() {
    this.toastr.success(this.msg);
  }

  showError() {
    this.toastr.error(this.msg);
  }

  archiveDataroom(dataroom) {
    console.log("Archive dataroom");
    this.dataRoomService
      .archivedRequestForDataroom(dataroom.id)
      .subscribe((res) => {
        this.msg = "Request has been send successfully for Archive";
        this.showSuccess();
      });
  }

  deleteDataroom(dataroom) {
    console.log("Delete Dataroom Id", dataroom.id);
    this.dataRoomService.deleteSingleDataroom(dataroom.id).subscribe((res) => {
      this.msg = "Request has been send successfully for Delete!";
      this.showSuccess();
    });
  }

  update: any = {
    dataroom: "",
    clone_data: "",
    dataroom_name: "",
    user_group: false,
  };

  cloneExistingDataroom() {
    this.dataRoomService.cloneDataRoom(this.update).subscribe(
      (res) => {
        this.msg = "Dataroom successfully clone";
        this.showSuccess();
        console.log("serializer data is ", res);
        // this.datarooms.push(res);
        this.getAllDataRooms();
      },
      (error) => {
        this.msg = "Internal error occurred !";
        // this.is_dataroom_exist = true;
        // this.errors = error;
        // console.log(error)
        this.showError();
      }
    );
    console.log("Delete Dataroom Id", this.update);
  }

  contactSupportTrial(dataroom) {
    this.dataRoomService.contactSupportTrial(dataroom).subscribe((res) => {
      this.msg =
        "We have contacted the support regarding this matter through mail!!";
      this.showSuccess();
    });
  }
}
