import { ToastrService } from 'ngx-toastr';
import { DataRoomService } from '../../../../services/index';
import { Router, ActivatedRoute } from '@angular/router';
import { FormBuilder, FormGroup, FormArray, FormControl, Validators } from '@angular/forms';
import { UploadOutput, UploadInput, UploadFile, humanizeBytes, UploaderOptions } from 'ngx-uploader';
import { BaseUrlClass, ApiListClass } from '../../../../common/index';
import { Component, OnInit } from '@angular/core';
import { Location } from '@angular/common';
import * as moment from 'moment';
import { TimezoneService } from '../../../../services/timezone.service';

@Component({
  selector: 'app-voting-status',
  templateUrl: './voting-status.component.html',
  styleUrls: ['./voting-status.component.css']
})
export class VotingStatusComponent implements OnInit {

 voteId:any;
dataroomId:any;
 timezone:any;
  constructor(private dataRoomService: DataRoomService,
              private toastr : ToastrService, 
              private router : Router, 
              private route: ActivatedRoute, 
              private _fb : FormBuilder,
              public baseUrlclass :BaseUrlClass,private _location: Location,private timeZone:TimezoneService) { 

  	this.route.params.subscribe(params => {
        this.voteId =  params.voteId;
        this.getVoteResultList(this.voteId);
        this.getVoteResultStatus(this.voteId);
        });
    this.dataroomId = (localStorage.getItem("currentDataroomId")).toString();
    this.getSingleDataroom(this.dataroomId);
    this.timezone = this.timeZone.userTimeZone;
  }

  ngOnInit() {
  }

  ExportVoterStatus(){
  this.dataRoomService.ExportVoterStatusReport(this.voteId, this.dataroom_name, this.current_date)
  .subscribe((res)=>{
    console.log("Export Overview Successfully")
  })
}

  dataroom_detail:any;
current_date:any;
dataroom_name:any;
  getSingleDataroom(dataroomId){
  this.dataRoomService.getSingleDataroom(dataroomId)
    .subscribe((res)=>{
      this.dataroom_detail = res;
      this.dataroom_name = res.dataroom_name;
      // this.avatarUrl = this._base_url+this.dataroom_detail.dataroom_admin_data.member.avatar;
      // this.avatarUrl = this.avatarUrl.replace("//media/", "/media/");
      // this.avatarUrl = 'assets/images/avatar-not.png';
      let todays_date = new Date();
      this.current_date = moment(todays_date).format('YYYY-MM-DD hh-mm-ss a');
              
      })  
  }

  voteResultList:any;
  getVoteResultList(voteId){
    console.log(3434);
    this.dataRoomService.getVotingResult(voteId)
    .subscribe((res)=>{
        console.log(res);
        this.voteResultList = res;

      })

  } 

  geBack(){
	this._location.back();
}

  voteResultStatus:any;
  getVoteResultStatus(voteId){
    console.log(3434);
    this.dataRoomService.getVoteCount(voteId)
    .subscribe((res)=>{
        console.log(res);
        this.voteResultStatus = res;

      })

  }

}
