import { Component, OnInit } from "@angular/core";
import { Router, ActivatedRoute } from "@angular/router";
import { DataRoomService } from "../../../services/dataroom_service";
import { BaseUrlClass, ApiListClass } from "../../../common/index";
import { Spinkit } from "ng-http-loader";
import { TimezoneService } from "../../../services/timezone.service";
import * as moment from "moment";

@Component({
  selector: "app-member-info",
  templateUrl: "./member-info.component.html",
  styleUrls: ["./member-info.component.css"],
})
export class MemberInfoComponent implements OnInit {
  // public spinkit = Spinkit;
  id: any;
  dataroomId: any;
  timezone: any;
  moment: any = moment;

  baseUrl: any;
  constructor(
    private route: ActivatedRoute,
    private dataRoomService: DataRoomService,
    private baseUrlclass: BaseUrlClass,
    private timeZone: TimezoneService
  ) {
    this.dataroomId = localStorage.getItem("currentDataroomId").toString();
    this.baseUrl = this.baseUrlclass.baseUrl;
    this.timezone = this.timeZone.userTimeZone;
    this.route.params.subscribe((params) => {
      this.id = params.id;
      this.getUserLastView();
      this.getUsersMember();
      this.getUserActivity();
    });
  }

  ngOnInit() {
    this.getUserInfo();
  }
  currentuser: any;
  getUserInfo() {
    this.dataRoomService.getUserProfile().subscribe((res) => {
      this.currentuser = res;
    });
  }

  user: any;
  getUsersMember() {
    this.dataRoomService
      .GetUserGroups(0, this.dataroomId, false)
      .subscribe((res) => {
        console.log(res);
        this.user = res.users.filter(
          (res) => res.member.id === parseInt(this.id)
        )[0];
      });
  }

  activity: any;
  last_viewd: any;

  getUserLastView() {
    this.dataRoomService
      .GetUserDataroomLastView(this.dataroomId, this.id)
      .subscribe((res) => {
        this.last_viewd = res.created_date;
        console.log(this.last_viewd);
      });
  }

  getUserActivity() {
    this.dataRoomService
      .getActivityUser(this.dataroomId, this.id)
      .subscribe((res) => {
        this.activity = res;
        console.log(res);
      });
  }

  goToViewerPage(folder) {
    console.log("folder id is", folder);
    this.dataRoomService.getFilesUpdated(folder.id, "view").subscribe((res) => {
      let token = localStorage.getItem("token");
      document.cookie = "token=" + token;
    });
  }
}
