import { Component, OnInit } from "@angular/core";
import { DataRoomService } from "../../../services/dataroom_service";
import { Chart } from "angular-highcharts";

@Component({
  selector: "app-usage-report",
  templateUrl: "./usage-report.component.html",
  styleUrls: ["./usage-report.component.css"],
})
export class UsageReportComponent implements OnInit {
  dataroomId: any;
  constructor(private dataRoomService: DataRoomService) {
    this.dataroomId = localStorage.getItem("currentDataroomId").toString();
  }

  ngOnInit() {
    this.getDateWise();
  }
  data: any;
  chart: any;
  get_dataroom_usage_details() {
    console.log("get_dataroom_usage_details");
    var todays =
      this.to_date.getFullYear() +
      "-" +
      (this.to_date.getMonth() + 1) +
      "-" +
      this.to_date.getDate();
    var first =
      this.from_date.getFullYear() +
      "-" +
      (this.from_date.getMonth() + 1) +
      "-" +
      this.from_date.getDate();

    this.dataRoomService
      .get_dataroom_usage_details_for_graph(this.dataroomId, first, todays)
      .subscribe((res) => {
        this.data = res;
        console.log("this.data ", first);
        console.log("this.data ", this.data);
        this.chart = new Chart({
          chart: {
            plotBackgroundColor: null,
            plotBorderWidth: null,
            plotShadow: false,
            type: "pie",
          },
          title: {
            text: "",
          },
          tooltip: {
            pointFormat: "{series.name}: <b>{point.percentage:.1f}%</b>",
          },
          plotOptions: {
            pie: {
              allowPointSelect: true,
              cursor: "pointer",
              dataLabels: {
                enabled: false,
              },
              showInLegend: true,
            },
          },
          credits: {
            enabled: false,
          },
          series: [
            {
              name: "Usage(MB)",
              data: [
                {
                  name: "Used",
                  y: res.dataroom_consumed,
                  color: "grey",
                },
                {
                  name: "Free",
                  y: res.dataroom_free,
                  color: "lightblue",
                },
              ],
            },
          ],
        });
      });
    // show chart data
  }

  from_date: any;
  to_date: any;
  changeDateWise(from_date, to_date) {
    console.log("in change datewise");
    this.to_date = to_date;
    this.from_date = from_date;
    this.get_dataroom_usage_details();
  }

  getDateWise() {
    var today = new Date();
    this.to_date = new Date(
      today.getFullYear(),
      today.getMonth(),
      today.getDate()
    );
    this.from_date = new Date(
      today.getFullYear() - 100,
      today.getMonth() - 1,
      today.getDate()
    );
    this.get_dataroom_usage_details();
  }
}
