ProperSelection(value){
  
  this.all_contacts;
  if (value==0){
    this.select = true
    this.all_contacts_groups.forEach((res)=>{
      res.select = false
    })
    this.getAllContacts();
  }else{
    this.select = false
    this.all_contacts_groups.forEach((res)=>{
      if (res.id == value){
        res.select = true
      }else{
        res.select = false
      }
      
    })
    this.getAllContactGroupMembers(value);
  }
}

