import { Component, OnInit } from '@angular/core';
import { DataRoomService } from '../../../services/dataroom_service';
import { ToastrService } from 'ngx-toastr';
import * as moment from 'moment';


@Component({
  selector: 'app-index-report',
  templateUrl: './index-report.component.html',
  styleUrls: ['./index-report.component.css']
})
export class IndexReportComponent implements OnInit {
  dataroomId:any;
  msg:any;

  constructor(private dataRoomService: DataRoomService,
  			  private toastr : ToastrService ) { 
  	this.dataroomId = (localStorage.getItem("currentDataroomId")).toString();
    this.getSingleDataroom(this.dataroomId);

  }

member_id:any=0;
  ngOnInit() {
  	// this.GetIndexReports();
    this.GetDataroomMembers();
  }

members:any;
GetDataroomMembers(){
  this.dataRoomService.getDataroomMembers(this.dataroomId)
    .subscribe((res)=>{
      this.members = res;
      
  })
}

dataroom_detail:any;
current_date:any;
dataroom_name:any;
  getSingleDataroom(dataroomId){
  this.dataRoomService.getSingleDataroom(dataroomId)
    .subscribe((res)=>{
      this.dataroom_detail = res;
      this.dataroom_name = res.dataroom_name;
      // this.avatarUrl = this._base_url+this.dataroom_detail.dataroom_admin_data.member.avatar;
      // this.avatarUrl = this.avatarUrl.replace("//media/", "/media/");
      // this.avatarUrl = 'assets/images/avatar-not.png';
      let todays_date = new Date();
      this.current_date = moment(todays_date).format('YYYY-MM-DD hh-mm-ss a');
              
      })  
  }


  showSuccess(){
    this.toastr.success( this.msg);
  }
  showError(){
    this.toastr.error( this.msg);
  }
  showInfo(){
    this.toastr.info( this.msg);
  }


  data:any;
  GetIndexReports(){
    
  	this.dataRoomService.getUserWiseIndexReport(this.dataroomId, this.member_id, this.dataroom_name, this.current_date)
		.subscribe((res)=>{
			this.msg = "SuccessFully Downloaded Index Report of Given User";
      this.showSuccess();
	})
	}

	GoToTrash(index_id, i){
		this.dataRoomService.DeleteIndexReports(index_id)
			.subscribe((res)=>{
				this.data.splice(i,1)
				this.msg = "Index Report successfully deleted !";
		      this.showInfo();
			})

	}

}
