import { Component, OnInit, ViewEncapsulation } from '@angular/core';
import { FormGroup, FormControl, Validators } from '@angular/forms';
import { ToastrService } from 'ngx-toastr';
import { DataRoomService } from '../../services/index';
import { PasswordValidation } from '../../signup/custom-validator';
import { BaseUrlClass, ApiListClass } from '../../common/index';
import { Location } from '@angular/common';

@Component({
  selector: 'app-user-forgot-pass',
  templateUrl: './user-forgot-pass.component.html',
  styleUrls: ['./user-forgot-pass.component.css'],
  encapsulation: ViewEncapsulation.None
})
export class UserForgotPassComponent implements OnInit {

  passwordForm : FormGroup;
  msg : string ;
  user : any;
  errors : any;
  is_error : boolean = false;
  _base_url : string = "";
  constructor(private toastr : ToastrService, 
              private dataRoomService : DataRoomService, 
              private baseUrlClass : BaseUrlClass,
              private location: Location,
              ) { 
    this._base_url = this.baseUrlClass.baseUrl;
  }

  ngOnInit() {
    this.createChangePassword();
    this.getUserInfo();
  }

goBack(){
  this.location.back();
  }

   createChangePassword() { 
  
  this.passwordForm = new FormGroup({
        current_password: new FormControl('', [
            Validators.minLength(8),
            Validators.maxLength(40),
            Validators.required
        ]),
        new_password: new FormControl('', [
            Validators.minLength(8),
            Validators.maxLength(40), 
            Validators.required
        ]),
        confirm_new_password: new FormControl('', [
            Validators.minLength(8),
            Validators.maxLength(40),
            Validators.required
        ])
    });//,{validators: PasswordValidation.MatchPassword});
  }

    showSuccess(){
    this.toastr.success( this.msg);
    }


    showError(){
    this.toastr.error( this.msg);
    }

  submitNewPassword(){
    console.log("password form value", this.passwordForm.value);
    this.dataRoomService.changeUserPassword(this.passwordForm.value)
      .subscribe(data=>{
        //console.log(res.data);
            this.msg = "Password successfully changed"
            this.showSuccess()
          
        },
      error => {
        this.errors = error.error.error;
        this.msg = this.errors;
        console.log(error)
        this.showError();
        this.is_error = true;
    
        setTimeout(()=>{    
            this.is_error = false;
 },5000);
      }, 

       () => {
              // No errors, route to new page
            }


      )

}

avatarUrl:any;
  getUserInfo(){
    this.dataRoomService.getUserProfile()
    .subscribe((res)=>{
      this.user = res;
      this.avatarUrl = this._base_url+this.user.avatar;
      this.avatarUrl = this.avatarUrl.replace("//media/", "/media/");
      
      })
  }

}