export class FileNode {
  children: FileNode[];
  filename: string;
  type: any;
  timezone:any;

}

/** Flat node with expandable and level information */
export class FileFlatNode {
  filename: string;
  type: any;
  level: number;
  expandable: boolean;
  timezone:any;
}

@Injectable()
export class FileDatabase {
  dataChange: BehaviorSubject<FileNode[]> = new BehaviorSubject<FileNode[]>([]);

  get data(): FileNode[] { return this.dataChange.value; }

  constructor(private dataRoomService: DataRoomService) {
    this.initialize();
  }

  initialize() {
    let dataroomId = (localStorage.getItem("currentDataroomId"));
    this.dataRoomService.getFoldersHierarchy(parseInt(dataroomId))
    .subscribe((res)=>{
    // Parse the string to json object.
    const dataObject =res; //JSON.parse(res);

    // Build the tree nodes from Json object. The result is a list of `FileNode` with nested
    //     file node as children.
    const data = this.buildFileTree(dataObject, 0);

    // Notify the change.
    this.dataChange.next(data);
  })
  }

  /**
   * Build the file structure tree. The `value` is the Json object, or a sub-tree of a Json object.
   * The return value is the list of `FileNode`.
   */
  buildFileTree(value: any, level: number): FileNode[] {
    
    let data: any[] = [];
    
    for (let k in value) {
      
        let v = value[k];

        let node = new FileNode();
        node.filename = `${k}`;
        if (v === null || v === undefined || Object.keys(v).length == 0) {
          // no action
        } else if (typeof v === 'object') {
          
            node.children = this.buildFileTree(v, level + 1);
                  
        } else {
          node.type = v;
        }
        data.push(node);
      }
      
    
      console.log("data is"+data);
    return data;
  }
}

