import {map} from 'rxjs/operators';
import { Injectable } from '@angular/core';
import { Http, Headers, Response } from '@angular/http';
import { Observable } from 'rxjs';

import { BaseUrlClass, ApiListClass } from '../common/index';
import { RequestOptions, ResponseContentType  } from '@angular/http';
import { HttpEvent, HttpEventType, HttpHandler, HttpInterceptor, HttpRequest,HttpResponse,  HttpClient, HttpHeaders } from '@angular/common/http';
import { catchError, tap } from 'rxjs/operators';


@Injectable()
export class AuthenticationService {
    private base_url : string;
    private token:string;
    constructor(private http: Http, private base: BaseUrlClass, private apiListClass: ApiListClass, private httpget: HttpClient,) {
      this.base_url = base.baseUrl;
      this.token = "token "+localStorage.getItem("token");
     }

    login(username: string, password: string) {
        
        return this.http.post(this.base_url+this.apiListClass.login, JSON.stringify({ username: username, password: password })).pipe(
            map((response: Response) => {
              
                // login successful if there's a jwt token in the response
                let token = response.json();
                if (token.token) {

                    document.cookie = "token="+token.token;
                    // store user details and jwt token in local storage to keep user logged in between page refreshes
                    console.log("token is:", token.token);
                    localStorage.setItem('token', token.token);
                    localStorage.setItem('user', JSON.stringify(token.user));
                    

                }
                 return token;
            }));
    }

    logout() {
        // remove user from local storage to log user out
        this.httpget.get(this.base_url+"logout",  {
        headers: new HttpHeaders().set('Authorization', this.token),
          }).pipe();
        console.log(1234);
        var d = new Date();
        d.setTime(d.getTime());
        var expires = d.toUTCString();
        document.cookie = "token=; expires="+expires+"; path=/;";

        localStorage.clear();
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        localStorage.removeItem('usertoken');

    }



}
